## A. New Year and Rating 

&nbsp;

根据每一次比赛前的等第列出不等式，若最终不等式右端无穷大，则Infinity，若右小于左，则Impossible，否则确定原值为右端最大值，知道原值后加上所有得分即为最终值。

```c++
#include<iostream>
#include<algorithm>
using namespace std;
const int INF = 0x3f3f3f3f;
int main() {
	int n;
	cin >> n;
	int high_div2 = -INF;
	int low_div1 = INF;
	int so_far = 0;
	for (int i = 0; i < n; ++i) {
		int change, division;
		cin >> change >> division;
		if (division == 2)
			high_div2 = max(high_div2, so_far);
		else
			low_div1 = min(low_div1, so_far);
		so_far += change;
	}
	if (high_div2 == -INF)
		cout << "Infinity" << endl;
	else if (high_div2 >= low_div1)
		cout << "Impossible" << endl;
	else
		cout << 1899 - high_div2 + so_far << endl;
	return 0;
}
```

