## C. Elections

&nbsp;

1. 知道要得几票，如何确定最小消耗钱数？

   从每个候选人中扣除，直至他们的票数都小于该值，从所有选票中取，直至我的票数等于该值。

2. 如何知道得几票？

   三分查找。

```c++
#include<iostream>
#include<vector>
#include<algorithm>
#include<cstring>
using namespace std;
#define ll long long
typedef pair<ll, int> pii;
int n, m;
vector<pii>vc,G[3050];
ll cost(int k) {
	ll res = 0;
	int get = G[1].size();
	vc.clear();
	for (int i = 2; i <= m; i++) {
		for(int j = 0; j < G[i].size(); j++) {
			if (G[i].size() - j >= k) {
				res += G[i][j].first;
				get++;
			}
			else vc.push_back(G[i][j]);
		}
	}
	sort(vc.begin(), vc.end());
	for (int i = 0; i < k - get; i++) {
		res += vc[i].first;
	}
	return res;
}
int main() {
	cin.sync_with_stdio(false);
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		ll p, mon;
		cin >> p >> mon;
		if (p != 1)vc.push_back(pii(mon, i));
		G[p].push_back(pii(mon, i));
	}
	sort(vc.begin(), vc.end());
	for (int i = 1; i <= m; i++) {
		sort(G[i].begin(), G[i].end());
	}
	int st = G[1].size();
	int ed = n;
	while (ed-st>2) {
		int p1 = ((st + ed) >> 1);
		int p2 = ((p1 + ed) >> 1);
		if (cost(p1) < cost(p2))ed = p2;
		else st = p1;
	}
	ll ans = cost(st);
	for (int i = st+1; i <= ed; i++) {
		ans = min(ans, cost(i));
	}
	cout << ans;
	return 0;
}
```

