## D. Neko does Maths

## &nbsp;

已知a，b，求a+k，b+k的最小公倍数的最小值。

即求$(a+k)(b+k)*gcd(a+k,b+k)$，我们知道$gcd(m,n)=gcd(m-n,n)$，故$gcd(a+k,b+k)=gcd(a-b,b+k)$，gcd(a-b,b+k)必然是(a-b)的因数，而(a-b)已知，因此枚举其因数为 i ，假设其为(a-b)与(b+k)的gcd，则i也是(b+k)的因数，b原本不是i的倍数，加上k后为倍数。由于已知**a+i-a%i为i的倍数**，则**且(a-b)为 i 的倍数**，则((a-b)-(a+i-a%i))为i的倍数，即(b+i-a%i)为i的倍数，得到k。之后枚举出最小值。

```c++
#include<iostream>
#include<cmath>
using namespace std;
#define ll long long
ll gcd(ll a, ll b) {
	if (a == 0)
		return b;
	return gcd(b%a, a);
}
ll a, b;
int main() {
	cin >> a >> b;
	if (a == b) {
		cout << 0;
		return 0;
	}
	if (a > b)swap(a, b);//a<b
	ll gp = b - a;
	ll ans = 0;
	ll mina = a * b / gcd(a, b);
	for (ll i = 1; i <= sqrt(gp) + 1; i++) {
		if (gp%i == 0) {
			ll k = i - b % i;
			ll nw = (a + k)*(b + k) / gcd(a + k, b + k);
			if (nw < mina) {
				mina = nw;
				ans = k;
			}
			k = gp / i - b % (gp / i);
			nw = (a + k)*(b + k) / gcd(a + k, b + k);
			if (nw < mina) {
				mina = nw;
				ans = k;
			}
		}
	}
	cout << ans;
	return 0;
}
```

