## E. Weakness and Poorness

&nbsp;

1. DP求子数组元素和绝对值的最大值
2. 三分查找使最大值最小的x

```c++
#include<iostream>
#include<cmath>
#include<algorithm>
#include<cstring>
using namespace std;
const int maxn = 2e5 + 5;
#define ll long long
double a[maxn];
int n;
double mx, mn;
double calc(double k) {
	double res1 = 0;
	double res2 = 0;
	double sum1 = 0, sum2 = 0;
	for (int i = 1; i <= n; i++) {
		sum1 = max(sum1 + a[i]+k, a[i]+k);
		res1 = max(sum1, res1);
		sum2 = min(sum2 + a[i]+k, a[i]+k);
		res2 = min(sum2, res2);
	}
	return max(fabs(res1), fabs(res2));
}
int main() {
	cin.sync_with_stdio(false);
	cin >> n;
	for (int i = 1; i <= n; i++) {
		double p;
		cin >> p;
		a[i] = p;
		if (p >= 0)mx = max(p, mx);
		else mn = min(mn, p);
	}
	int dt = 100;
	double st = 0 - mx, ed = 0 - mn;
	while (dt--) {
		double p1 = st+(ed-st)/3;
		double p2 = st+(ed-st)*2/3;
		double c1 = calc(p1), c2 = calc(p2);
		//cout << c1 << c2<<endl;
		if (c1 > c2) {
			st = p1;
		}
		else
			ed = p2;
	}
	double ans = min(calc(st), calc(ed));
	printf("%.10f", ans);
	return 0;
}
```

