## F. Prefix Sum Primes

## &nbsp;

先打印出素数表（埃氏），再用二和一凑出表中数，先尽量用2。

```c++
#include<iostream>
#include<algorithm>
#include<map>
using namespace std;
const int maxn = 2e5 + 5;
int n, ans;
map<int, int>mp; 
bool is_prime[2*maxn];
int prime[2*maxn];
void sieve(int n) {
	int p = 0;
	for (int i = 0; i < n; i++) is_prime[i] = 1;
	is_prime[0] = is_prime[1] = 0;
	for (int i = 2; i <= n; i++) {
		if (is_prime[i]) {
			prime[p++] = i;
			for (int j = 2 * i; j <= n; j += i)is_prime[j] = 0;
		}
	}
}
int main() {
	std::ios::sync_with_stdio(false);
	cin >> n;
	for (int i = 0; i < n; i++) {
		int a;
		cin >> a;
		mp[a]++;
	}
	int now = 0;
	int t = 0;
	sieve(2 * (n+5));
	int k=0;
	while (mp[1] > 0 && mp[2] > 0) {
		int to = prime[t] - now;
		int num_2 = min(mp[2], to / 2);
		mp[2] -= num_2;
		to -= (2 * num_2);
		for (int i = 0; i < num_2; i++)
			cout << 2 << ' ';
		int num_1 = min(mp[1], to);
		mp[1] -= num_1;
		to -= num_1;
		for (int i = 0; i < num_1; i++)
			cout << 1 << ' ';
		now = prime[t];
		t++;
	}
	if (mp[1] > 0) {
		for (int i = 0; i < mp[1];i++)
			cout << 1 << ' ';
	}
	else if (mp[2] > 0) {
		for (int i = 0; i < mp[2];i++)
			cout << 2 << ' ';
	}
	return 0;
}
```

