## G. Painting the Fence

&nbsp;

线段树+延迟标记，叶节点记录实际颜色，其他节点记录被涂的颜色，即懒标记。

查询和更新时，向下推颜色。

```c++
#include<iostream>
#include<algorithm>
#include<queue>
using namespace std;
#define lson 2*id
#define rson 2*id+1
const int maxn = 3e5 + 5;
int n, m;
int a[maxn];
deque<int>q[maxn];
struct P {
	int color;
	int l, r;
}tr[maxn*4];
void down(int id) {
	int& x = tr[id].color;
	if (x != 0) {
		tr[lson].color = x;
		tr[rson].color = x;
		x = 0;
	}
}
void update(int id,int st,int ed,int x) {
	if (st <= tr[id].l&&ed>=tr[id].r) {
		tr[id].color = x;
		return;
	}
	down(id);
	int mid = (tr[id].l + tr[id].r) >> 1;
	if (ed <= mid)
		update(lson, st, ed, x);
	else if (st > mid)
		update(rson, st, ed, x);
	else {
		update(lson, st, mid, x);
		update(rson, mid+1, ed, x);
	}
}
void build(int l, int r, int id) {
	tr[id].color = 0;
	tr[id].l = l;
	tr[id].r = r;
	if (l == r) { tr[id].color = a[l]; return; }
	int mid = (l + r) >> 1;
	build(l,mid,lson);
	build(mid+1,r,rson);
}
int query(int id,int que) {
	if (tr[id].l == tr[id].r)
		return tr[id].color;
	down(id);
	int mid = (tr[id].l + tr[id].r) >> 1;
	if (que <= mid)return query(lson, que);
	else return query(rson, que);
}
int main() {
	cin.sync_with_stdio(false);
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
		q[a[i]].push_back(i);
	}
	build(1, n, 1);
	cin >> m;
	for (int i = 0; i < m; i++) {
		int x;
		cin >> x;
		if (q[x].size() <= 1)
			continue;
		int st = q[x].front(), ed = q[x].back();
		while (query(1, st) != x&&!q[x].empty()) {
			q[x].pop_front();
			if (!q[x].empty())
				st = q[x].front();
		}
		while (query(1, ed) != x&&!q[x].empty()) {
			q[x].pop_back();
			if (!q[x].empty())
				ed = q[x].back();
		}
		if (q[x].size() > 1) {
			update(1, st, ed, x);
		}
	}
	for (int i = 1; i <= n; i++) {
		cout << query(1, i) <<' ';
	}
	return 0;
}
```

