## K. Santa Claus and Robot

&nbsp;

双指针，记录开头和结尾，若下一步与中间相矛盾，则答案+1，开头移到结尾。

```c++
#include<iostream>
#include<map>
#include<vector>
#include<string>
using namespace std;
const int maxn = 2e5 + 5;
int n;
map<char, int>mp;
int st, ed;
int ans;
int main() {
	std::ios::sync_with_stdio(false);
	cin >> n;
	string s;
	cin >> s;
	int len = n;
	while (ed < len) {
		char now = s[ed];
		if (now == 'L') {
			if (mp['L'] < 0) {
				st = ed;
				mp['U'] = 0;
				mp['L'] = 1;
				ans++;
			}
			else mp['L']++;
		}
		else if (now == 'R') {
			if (mp['L'] > 0) {
				st = ed;
				mp['U'] = 0;
				mp['L'] = -1;
				ans++;
			}
			else mp['L']--;
		}
		else if (now == 'U') {
			if (mp['U']<0) {
				st = ed;
				mp['U'] = 1;
				mp['L'] = 0;
				ans++;
			}
			else mp['U']++;
		}
		else {
			if (mp['U'] > 0) {
				st = ed;
				mp['U'] = -1;
				mp['L'] = 0;
				ans++;
			}
			else mp['U']--;
		}
		ed++;
	}
	ans++;
	cout << ans << endl;
	return 0;
}
```

