## A. Cells Not Under Attack

&nbsp;

&emsp;每次放棋子时，检查棋子所在的行和列是否已经有棋子，若没有，则将未受威胁的格子总数减去（行数+列数-1），若行或列上已经有棋子，则只减去行数或列数，分类讨论即可。

```c++
#include<iostream>
#include<queue>
#include<algorithm>
using namespace std;
#define ll long long
const int maxn = 1e5 + 5;
vector<int>x;
vector<int>y;
bool inx(int xi) {
	return binary_search(x.begin(), x.end(), xi);
}
bool iny(int yi) {
	return binary_search(y.begin(), y.end(), yi);
}
bool usedx[maxn];
bool usedy[maxn];
int numx, numy;
int main() {
	ll n, m;
	cin >> n >> m;
	long long T = n*n;
	for (int i = 0; i < m; i++) {
		int xi, yi;
		ll to_minus = 0;
		cin >> yi >> xi;
		if (T == 0) {
			cout << 0<<' ';
			continue;
		}
		if ((!usedx[xi]) && (!usedy[yi])) {
			to_minus = n + n - 1 - numx - numy;
			numx++;
			numy++;
			usedx[xi] = 1;
			usedy[yi] = 1;
		}
		else if ((!usedx[xi]) && usedy[yi]) {
			to_minus = n - numy;
			numx++;
			usedx[xi] = 1;
		}
		else if (usedx[xi] && (!usedy[yi])) {
			to_minus = n - numx;
			numy++;
			usedy[yi] = 1;
		}
		else if (usedx[xi] && usedy[yi])
			to_minus = 0;
		T -= to_minus;
		if (T < 0)
			T = 0;
		cout << T << ' ';
		//getchar();
	}
	//getchar();
	return 0;
}
```

