## C. Minimum Array

&nbsp;

&emsp;先利用lower_bound找到大于等于$n-a_i$的数，并erase掉。

若未找到，则从头开始找到第一个不为0的数。指向开头的指针+1。

**当所有元素b中都相等时，erase耗时太大，所以要选第一个。**

**<font size=5 color=red>注意先输出，再erase，否则会越界！！</font>**

```c++
#include<iostream>
#include<algorithm>
#include<vector>
using namespace std;
#define ll long long
const int maxn = 2e5 + 5;
int a[maxn];
vector<int>vc;
int main() {
	std::ios::sync_with_stdio(false);
	int n;
	cin >> n;
	for (int i = 0; i < n; i++) {
		cin >> a[i];
	}
	int st = 0;
	for (int i = 0; i < n; i++) {
		int tp;
		cin >> tp;
		vc.push_back(tp);
	}
	sort(vc.begin(), vc.end());
	for (int i = 0; i < n; i++) {
		int best = n - a[i];
		int pos = lower_bound(vc.begin() + st, vc.end(), best) - vc.begin();
		if (pos == vc.size() || vc[pos] == vc[0]) {	//针对所有数都相等的情况
			cout << (vc[st] + a[i]) % n<<' ';
			st++;
			continue;
		}
		if ((a[i] + vc[st] % n) < (vc[pos] + a[i]) % n) {
			cout << (a[i] + vc[st]) % n << ' ';
			st++;
		}
		else {
			cout << (a[i] + vc[pos]) % n << ' ';
			vc.erase(vc.begin() + pos);
		}
	}
	return 0;
}
```

