## D. Powerful array

&nbsp;

&emsp;裸的普通<u>[莫队](https://www.cnblogs.com/Paul-Guderian/p/6933799.html)</u>

```c++
#include<iostream>
#include<algorithm>
#include<cmath>
using namespace std;
#define ll long long
const int maxn = 2e5 + 50;
int n, t;
int a[maxn];
int unit;
ll ans;
int cnt[1000005];
ll res[maxn];
struct Node
{
	int st, ed;
	int idt;
}que[maxn];
bool cmp(Node a, Node b) {
	return (a.st / unit == b.st / unit) ? (a.ed < b.ed) : (a.st / unit < b.st / unit);
}
void add(int x) {
	ans += ((cnt[a[x]] << 1) + 1)*a[x];
	cnt[a[x]]++;
}
void del(int x) {
	ans -= ((cnt[a[x]] << 1) - 1)*a[x];
	cnt[a[x]]--;
}
int main() {
	ios::sync_with_stdio(false);
	cin >> n >> t;
	unit = sqrt(t);
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	for (int i = 1; i <= t; i++) {
		cin >> que[i].st >> que[i].ed;
		que[i].idt = i;
	}
	sort(que + 1, que + t + 1, cmp);
	int L = 0, R = 0;
	for (int i = 1; i <= t; i++) {
		while (L < que[i].st)del(L++);
		while (L > que[i].st)add(--L);
		while (R > que[i].ed)del(R--);
		while (R < que[i].ed)add(++R);
		res[que[i].idt] = ans;
	}
	for (int i = 1; i <= t; i++) {
		cout << res[i] << endl;
	}
	return 0;
}
```

