注意几点：

- 二分停止的条件是上下边界的差值小于 eps ，而非时间的值与t的差值小于 eps 。

- cout的double只能输出小数点后 6 位，要输出更多需在输出语句前加

  ```c++
  cout << setprecision(t);
  ```

  便可输出小数点后 t 位

代码：

```c++
#include<iostream>
#include<vector>
#include<cmath>
#include <iomanip>
using namespace std;
typedef pair<int, int> pii;
int n, t;
const double eps = 1e-9;
double c=0;
double ed, st;
vector<pii>vc;
double solve() {
	double ans = 0.0;
	for (auto it : vc) {
		ans += 1.0*it.first / (it.second + c);
	}
	return ans;
}
int main() {
	cin >> n >> t;
	int mins=1e9;
	for (int i = 0; i < n; i++) {
		int d, s;
		cin >> d >> s;
		if (s <mins)mins = s;
		vc.push_back(pii(d, s));
	}
	st = 0-mins;
	ed = 1e9;
	c = (st + ed)*1.0 / 2;
	double tmp;
	while (ed-st>=eps) {
		c = 1.0*(st + ed) / 2;
		tmp = solve() - t;
		if (tmp >=eps) {
			st = c;
		}
		else {
			ed = c;
		}
	}
	cout << setprecision(7);
	cout << c;
	return 0;
}
```

想到的解法比较rz，就是一层层地进入罐头，当遇到 ' { '，' [ '，' ( ' 时进入下一层罐头，当遇到 ' } '，' ] '，' ) '时检查与罐头开头是否相匹配，若不匹配则彻底false，反之，继续检查。

### 代码：



```c++
#include<iostream>
#include<string>
#include<map>
using namespace std;
const int maxn = 1005;
string s;
int now = 0;		//检查到下标为now的点
map<char, char>mp;   //对应情况
bool ok = true;		//是否正确
void solve(int len,int depth) {
	char st = s[now];
	now++;
	while(now<len){
		if (s[now] == '}' || s[now] == ']' || s[now] == ')') {
			if (s[now] != mp[st]) {
				ok = false;		//彻底false
			}
			return;
		}
		if (s[now] == '{' || s[now] == '[' || s[now] == '(') {
			solve(len, depth + 1);
		}
		now++;
	}
}
int main() {
	mp['{']='}';
	mp['['] = ']';
	mp['('] = ')';
	int N;
	cin >> N;
	for(int i=1;i<=N;i++) {
		ok = true;
		now = 0;
		cin >> s;
		if (s[0] != '{'&&s[0] != '['&&s[0] != '(') {//开头不是罐头，直接false
			cout << "NO" << endl;
			continue;
		}
		int len = s.length();
		solve(len, 0);
		if (ok && now == len - 1)	//ok正确且最后一个点是罐头盖子
			cout << "YES" << endl;
		else cout << "NO" << endl;
	}
	return 0;
}
```

要用掉数量最多的硬币，则要尽量用面额小的硬币。

从面额最小的硬币开始凑起，上限为有的硬币数或付清P所需最大硬币数。

下限为 0 或上限减去（25/当前硬币面额），意为若用之后的面额的硬币凑不出某一数值，则必然也凑不出该数值加25。命题在该数值大于当前面额时成立。

确定上下限后，对每种面额搜索。

```c++
#include<bits/stdc++.h>
using namespace std;
int p,v[4]={1,5,10,25},n[4];
int dfs(int i,int sum,int ans)//第i种硬币,已经兑换总额, 已经用的i-1种硬币的数量 
{
	if (sum==p) return ans;
	if (i==4) return -1;
	int high=min((p-sum)/v[i],n[i]),low=max(0,high-25/v[i]);
	for(int j=high;j>=low;j--)
	{
		int tem=dfs(i+1,sum+j*v[i],ans+j);
		if(tem!=-1) return tem;
	}
	return -1;
}
int main()
{	
	cin>>p;
	for(int i=0;i<4;i++)	cin>>n[i];
	int ans=dfs(0,0,0);
	if(ans==-1) cout<<"Impossible";
	else cout<<ans;
} 
