将每个环染色，以便判断是否可达（属于不同环的站点必然不可达），同时记录每个环的长度。

若两站点可达，任选一个方向记录两点距离，与走另一方向距离比较（环长-已记录的距离），选小的。

### 代码：

```c++
#include<iostream>
#include<queue>
#include<vector>
#include<algorithm>
#include<cstring>
using namespace std;
const int maxn = 1e5 + 5;
int color[maxn];
int len_color[maxn/2];
int num_color=0;
int N, q;
struct Node {
	int index;
	vector<Node*>neighbour;
}node[maxn];
typedef pair<Node*, int> pni;
int len_now = 0;
void paint_1(Node* a) {
	if (color[a->index] != -1)
		return;
	len_now++;
	color[a->index] = num_color;
	for (auto c : a->neighbour) {
		if (color[c->index] == -1) {
			paint_1(c);
		}
	}
}
void paint(Node* a) {
	len_now = 0;
	paint_1(a);
	len_color[num_color] = len_now;
	num_color++;
}
bool operator<(pni a, pni b) {
	return a.second < b.second;
}
bool visited[maxn];
int find(Node* a,Node* b) {
	memset(visited, 0, N+2);
	priority_queue<pni>pr;
	pr.push(pni(a, 0));
	Node* tmp = a;
	while (!pr.empty()) {
		pni tp = pr.top();
		Node* front = tp.first;
		pr.pop();
		for (auto c : front->neighbour) {
			if (!visited[c->index]) {
				visited[c->index] = true;
				if (c == b)
					return tp.second + 1;
				pr.push(pni(c, tp.second + 1));
			}
		}
	}


}
int main() {
