贪心

每次将一局的分数存入优先队列中，作为xjd的胜场分数。

进行假设，若xjd的分数大于oxx，说明有减少的余地，尝试从xjd的胜场中找出分数最小的，并减去，将其变为oxx的胜场。直到无法再减少。

### 代码：

```c++
#include<iostream>
#include<queue>
#include<algorithm>
using namespace std;
typedef long long ll;
const int maxn = 1e6+5;
ll arr[maxn];
ll n,k;
ll ans;
priority_queue<ll,vector<ll>, greater<ll> >win;
int main() {
	cin >> n >> k;
	for (ll i = 1; i <= n; i++) {
		cin >> arr[i];
	}
	ans = n + 1;
	ll score_oxx, score_xjd;
	score_oxx = k;
	score_xjd = 0;
	ll cnt = 0;
	for (ll i = 1; i <= n; i++) {
		win.push(arr[i]);
		score_xjd += arr[i];
		cnt++;
		while (score_xjd>score_oxx) {
			ll tp = win.top();
			if (score_xjd - tp >= score_oxx + tp) {
				score_xjd -= tp;
				score_oxx += tp;
				win.pop();
				cnt--;
			}
			else
				break;
		}
		if(score_xjd>=score_oxx)
			ans = min(ans, cnt);
	}
	if (ans == n + 1)cout << -1;
	else cout << ans;
	return 0;
}
```

