   	vector<int>cara;
   	character.push_back(3); character.push_back(2); character.push_back(2); character.push_back(3);
   	for (int i = 0; i < K; i++)
   		cara.push_back(i);		//初始特征空间
   	Node* root=build(dat,cara);

   	//test
