    while(~scanf("%d%d",&a,&b))
    {
        if(a>b)
            swap(a,b);
        int ans=floor((b-a)*(sqrt(5)+1)/2); //判断是否是奇异局势
        if(a==ans)
            printf("second win\n");
        else
            printf("first win\n");
    }
    return 0;
}
